const staticData = $getWorkflowStaticData('node');

const attempts = staticData.attempts ?? 0;
const newAttempts = attempts + 1;

if (newAttempts >= 3) {
    staticData.attempts = 0; // reset for next execution
    return [{ json: { ...$json, attempts: newAttempts, is_failed: 'yes' } }];
}

staticData.attempts = newAttempts;
return [{ json: { ...$json, attempts: newAttempts, is_failed: 'no' } }];

const output = $json.output || '';

const requiredKeywords = [
    ['Appendix', 'Annexes', 'Annexe'],
    ['References', 'Références'],
    ['Legal', 'Juridique', 'Documents'],
];

const missingKeywords = requiredKeywords.filter(group =>
    !group.some(kw => output.toLowerCase().includes(kw.toLowerCase()))
);

return [{
    json: {
        ...$json,
        keywords_valid: missingKeywords.length === 0 ? 'true' : 'false',
        missing_keywords: missingKeywords.map(g => g[0]),
    }
}];

const output = $json.output || '';
const minLength = 400;
const length_valid = output.length >= minLength ? 'true' : 'false';

return [{
  json: {
    ...$json,
    length_valid: length_valid,
    actual_length: output.length,
  }
}];

const body = $json.body || $json;
const sectionId = body.section_id;
const input = body.input_json || {};
const context = body.plan_context || {};
const language = body.language || 'english';
const businessPlanId = body.business_plan_id;

const headings = language === 'french' ? `
- Annexes
- Références
- Documents juridiques
` : `
- Appendix
- References
- Legal Documents
`;

let documentsList = 'None provided';
if (input.selected_documents) {
  documentsList = input.selected_documents.split(',').map(d => '- ' + d.replace(/_/g, ' ')).join('\n');
}

const prompt = `
You are a senior business consultant writing a professional business plan.

Your task: Write the "Appendices" section of a business plan.
Output language: ${language}

## COMPANY CONTEXT
${context.company_presentation || 'Not provided'}

## FINANCIAL CONTEXT
${context.financial_plan || 'Not provided'}

## RISK CONTEXT
${context.risk_opportunity || 'Not provided'}

## APPENDIX INPUT DATA
- Selected Documents to Include:\n${documentsList}
- Custom References & Additional Docs: ${input.custom_references || 'Not provided'}

## RULES
- Format the Table of Appendices as labeled paragraphs, NOT as a 
  markdown table. Use this format for each entry:

  Appendix A — [Title]
  [1-2 sentence description]
  Status: Attached separately / Available upon request
- For each document, assign an Appendix letter (e.g. Appendix A), a formal title, and a 1-2 sentence description based on the context.
- Explicitly state that these documents are \"Attached separately\" or \"Available upon request\".
- Cross-reference the context sections: if the financial plan mentions assumptions or the risk section mentions external reports, flag those as recommended appendix items even if not explicitly listed in the input.
- Write at least 300 words.
- Use formal, professional business language throughout.
- Structure the section using these headings: ${headings}
- NEVER repeat a sentence, phrase, or paragraph already written earlier in your response. Each paragraph MUST introduce new information.
- If no references were provided in the input, write: "Market research references will be added prior to submission." Do NOT fabricate report titles, publisher names, or citations.

## OUTPUT FORMAT
Return your response using EXACTLY this structure. Nothing before. Nothing after.

=== SECTION_TEXT ===
[Write the full Appendices section here, using the headings above]

=== MEMORY_SUMMARY ===
Documents Attached: [comma-separated list of document titles, or "None provided"]
Key References: [comma-separated list of sources or URLs, or "None provided"]
Certifications: [any licenses, permits, or certifications mentioned, or "None provided"]
`;

return [{
  json: {
    prompt,
    sectionId: sectionId,
    business_plan_id: businessPlanId,
    section_name: 'appendices',
    language,
    input_json: input,
  }
}];

const raw = $('AI Agent1').item.json.output || '';

let textMatch = raw.match(/=== SECTION_TEXT ===([\s\S]*?)=== MEMORY_SUMMARY ===/);
let memMatch  = raw.match(/=== MEMORY_SUMMARY ===([\s\S]*?)$/);

if (!textMatch) {
  const parts = raw.split(/===\s*MEMORY_SUMMARY\s*===/i);
  textMatch = parts.length > 1 ? [null, parts[0].replace(/===.*?===/i, '').trim()] : null;
}
if (!memMatch) {
  const parts = raw.split(/===\s*MEMORY_SUMMARY\s*===/i);
  memMatch = parts.length > 1 ? [null, parts[1].trim()] : null;
}

let section_text   = textMatch ? textMatch[1].replace(/^===.*?===\n?/i, '').trim() : raw.trim();
section_text = section_text.replace(/===\s*[^=]*?\s*===/g, '').trim();
const memory_summary = memMatch ? memMatch[1].trim() : '';

const promptText   = $('Build Prompt1').item.json.prompt || '';
const tokens_input  = Math.round(promptText.length / 4);
const tokens_output = Math.round(raw.length / 4);
const tokens_total  = tokens_input + tokens_output;

const buildData = $('Build Prompt1').item.json;
return [{
  json: {
    ...buildData,
    output: section_text,
    memory_summary,
    tokens_input,
    tokens_output,
    tokens_total,
  }
}];
